      globalCalendarItems: 'id',
      globalMessages: 'messageId',
      globalPosts: 'postId',
      globalThemes: 'themeKey',
      globalGroups: 'groupKey',
      softwareVersions: 'softwareId',
      directoryUsers: 'userId',
      appSettings: 'key',
